#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        static char A[1000005];
        static char B[1000005];
        scanf("%s", A);
        scanf("%s", B);
        long long ans = 0;
        int nextLess = 0; // dp[i+1]
        for (int i = N-1; i >= 0; --i) {
            if (A[i] < B[i]) nextLess = 1;
            else if (A[i] > B[i]) nextLess = 0;
            // else keep nextLess as dp[i+1]
            ans += nextLess;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

